#!/usr/bin/env python3
"""Direct stdio test of an MCP server: initialize, list_tools, call_tool."""
import json
import subprocess
import sys
import time

def send(proc, msg):
    proc.stdin.write((json.dumps(msg) + "\n").encode())
    proc.stdin.flush()

def recv(proc, timeout=10.0):
    deadline = time.time() + timeout
    line = b""
    while time.time() < deadline:
        c = proc.stdout.read(1)
        if not c:
            time.sleep(0.05)
            continue
        line += c
        if c == b"\n":
            return json.loads(line)
    raise TimeoutError("no response")

def test_mcp(cmd, tool_name=None, tool_args=None, label=""):
    print(f"\n========== {label or cmd[0]} ==========")
    try:
        proc = subprocess.Popen(cmd, stdin=subprocess.PIPE, stdout=subprocess.PIPE, stderr=subprocess.PIPE, bufsize=0)
    except Exception as e:
        print(f"  FAILED to spawn: {type(e).__name__}: {e}")
        return

    try:
        # initialize
        send(proc, {
            "jsonrpc": "2.0", "id": 1, "method": "initialize",
            "params": {"protocolVersion": "2024-11-05", "capabilities": {}, "clientInfo": {"name": "stdio-test", "version": "0.1"}}
        })
        init_resp = recv(proc, timeout=30.0)
        srv_info = init_resp.get("result", {}).get("serverInfo", {})
        print(f"  initialized: {srv_info.get('name', '?')} v{srv_info.get('version', '?')}")

        # initialized notification
        send(proc, {"jsonrpc": "2.0", "method": "notifications/initialized"})

        # tools/list
        send(proc, {"jsonrpc": "2.0", "id": 2, "method": "tools/list", "params": {}})
        tools_resp = recv(proc, timeout=10.0)
        tools = tools_resp.get("result", {}).get("tools", [])
        print(f"  tools ({len(tools)}): {[t['name'] for t in tools]}")

        # tools/call
        if tool_name:
            send(proc, {
                "jsonrpc": "2.0", "id": 3, "method": "tools/call",
                "params": {"name": tool_name, "arguments": tool_args or {}}
            })
            call_resp = recv(proc, timeout=60.0)
            result = call_resp.get("result", {})
            content = result.get("content", [])
            if content and content[0].get("type") == "text":
                text = content[0]["text"]
                if len(text) > 800:
                    text = text[:800] + f"\n  ...[truncated, {len(text)} chars total]"
                print(f"  call {tool_name}({tool_args or '{}'}):\n{text}")
            else:
                print(f"  call result: {result}")
    except Exception as e:
        print(f"  test FAILED: {type(e).__name__}: {e}")
        try:
            err = proc.stderr.read(4000).decode("utf-8", errors="replace")
            if err:
                print(f"  stderr: {err[:1000]}")
        except Exception:
            pass
    finally:
        try:
            proc.stdin.close()
        except Exception:
            pass
        proc.terminate()
        try:
            proc.wait(timeout=2.0)
        except Exception:
            proc.kill()

CRUCIBLE = "/Users/mvid/Development/reliq/crucible/mcp"

# (label, command, health tool name, args)
TESTS = [
    ("kani-mcp",          [f"{CRUCIBLE}/kani-mcp/kani_mcp.py"],                    "check_kani_health",     {}),
    ("quint-mcp",         [f"{CRUCIBLE}/quint-mcp/quint_mcp.py"],                  "check_quint_health",    {}),
    ("verus-mcp",         [f"{CRUCIBLE}/verus-mcp/verus_mcp.py"],                  "check_verus_health",    {}),
